293	function authenticate(req: Request, res: Response, next: NextFunction): void {
294	  const authorization = req.header("Authorization");
295	  if (!authorization?.startsWith("Bearer ")) {
296	    res.status(401).json({ error: "unauthorized" });
297	    return;
298	  }
299	
300	  const token = authorization.slice("Bearer ".length).trim();
301	  try {
302	    const payload = jwt.verify(token, JWT_SECRET);
303	    if (typeof payload !== "object" || typeof payload.userId !== "number") {
304	      res.status(401).json({ error: "unauthorized" });
305	      return;
306	    }
307	
308	    const user = getUserById.get(payload.userId);
309	    if (!user) {
310	      res.status(401).json({ error: "unauthorized" });
311	      return;
312	    }
313	
314	    (req as AuthenticatedRequest).userId = payload.userId;
315	    next();
316	  } catch {
317	    res.status(401).json({ error: "unauthorized" });
318	  }
319	}
